import { useLocalStorage } from './useLocalStorage';

export default function App() {
  const [name, setName, removeName] = useLocalStorage('user-name', '');
  const [count, setCount] = useLocalStorage('counter', 0);

  return (
    <div style={{ padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1.5rem', maxWidth: '24rem' }}>
      <div>
        <label style={{ fontSize: '0.875rem', fontWeight: 500 }}>Name (syncs across tabs)</label>
        <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.25rem' }}>
          <input
            value={name}
            onChange={e => setName(e.target.value)}
            placeholder="Enter your name"
            style={{ flex: 1, padding: '0.375rem 0.5rem', border: '1px solid #d1d5db', borderRadius: '0.375rem', fontSize: '0.875rem' }}
          />
          <button onClick={removeName} style={{ padding: '0.375rem 0.75rem', border: '1px solid #d1d5db', borderRadius: '0.375rem', cursor: 'pointer', fontSize: '0.875rem' }}>Clear</button>
        </div>
      </div>
      <div>
        <p style={{ fontSize: '0.875rem', fontWeight: 500 }}>Counter: {count}</p>
        <button onClick={() => setCount(c => c + 1)} style={{ padding: '0.375rem 0.75rem', border: '1px solid #d1d5db', borderRadius: '0.375rem', cursor: 'pointer', marginTop: '0.25rem' }}>Increment</button>
      </div>
      <p style={{ fontSize: '0.75rem', color: '#6b7280' }}>Open this page in another tab — changes sync automatically.</p>
    </div>
  );
}

